    fn tokenToSymbol(self: *BaseParser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 66,
            .@"drop_stmt" => 71,
            .@"string_sq" => 76,
            .@"string_dq" => 77,
            .@"indent" => 82,
            .@"outdent" => 83,
            .@"kwarg_name" => 93,
            .@"read_pfx" => 96,
            .@"write_pfx" => 97,
            .@"suffix_q" => 106,
            .@"suffix_bang" => 107,
            .@"share_pfx" => 108,
            .@"integer" => 112,
            .@"bar_capture" => 116,
            .@"dot_lit" => 124,
            .@"ternary_if" => 131,
            .@"post_if" => 134,
            .@"minus_prefix" => 145,
            .@"move_pfx" => 147,
            .@"clone_pfx" => 148,
            .@"pin_pfx" => 149,
            .@"raw_pfx" => 150,
            .@"real" => 156,
            .@"true" => 157,
            .@"false" => 158,
            .@"dot_lbrace" => 163,
            .@"colon" => 67,
            .@"assign" => 69,
            .@"lparen" => 98,
            .@"comma" => 99,
            .@"rparen" => 102,
            .@"tilde" => 109,
            .@"lbracket" => 110,
            .@"rbracket" => 111,
            .@"dot" => 123,
            .@"ampersand" => 146,
            .@"star" => 151,
            .@"at" => 162,
            .@"rbrace" => 166,
            .@"lbrace" => 167,
            .@"bar" => 189,
            .@"caret" => 190,
            .@"lt" => 193,
            .@"gt" => 194,
            .@"plus" => 199,
            .@"minus" => 200,
            .@"slash" => 201,
            .@"percent" => 202,
            .@"fixed_assign" => 70,
            .@"arrow" => 103,
            .@"dotdot" => 127,
            .@"fat_arrow" => 128,
            .@"nullish" => 132,
            .@"plus_assign" => 140,
            .@"minus_assign" => 141,
            .@"star_assign" => 142,
            .@"slash_assign" => 143,
            .@"move_assign" => 144,
            .@"pipe" => 186,
            .@"or_sym" => 187,
            .@"and_sym" => 188,
            .@"eq" => 191,
            .@"ne" => 192,
            .@"le" => 195,
            .@"ge" => 196,
            .@"lshift" => 197,
            .@"rshift" => 198,
            .@"power" => 203,
            else => 2, // error
        };
    }

    fn identToSymbol(self: *BaseParser, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return symIdent;
        if (self.tryIdentAsKeyword(token, text)) |sym| return sym;
        return symIdent;
    }

    fn tryIdentAsKeyword(self: *BaseParser, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.stateStack.getLast();
        if (rig.keywordAs(text)) |id| {
            const idIdx = @intFromEnum(id);
            const sym = keywordToSymbol[idIdx];
            if (sym != 0 and getAction(state, sym) > 0) {
                self.lastMatchedId = @intCast(idIdx);
                return sym;
            }
            const fallback = keywordFallbackSymbol;
            if (fallback != 0 and getAction(state, fallback) > 0) {
                self.lastMatchedId = @intCast(idIdx);
                return fallback;
            }
        }
        return null;
    }

    pub fn parseProgram(self: *BaseParser) !Sexp {
        self.injectedToken = SYM_program_START;
        return self.doParse(SYM_program);
    }
    pub fn parseExpr(self: *BaseParser) !Sexp {
        self.injectedToken = SYM_expr_START;
        return self.doParse(SYM_expr);
    }
};

pub const Parser = if (@hasDecl(rig, "Parser")) rig.Parser else BaseParser;

// =============================================================================
// Top-level convenience helpers (one per start symbol)
// =============================================================================

/// Convenience: instantiate the (lang-extended) parser and parse a whole
/// program. Caller owns `result.parser` and must call `result.parser.deinit()`
/// when done with the returned tree (the tree references arena-allocated
/// memory owned by the parser).
///
/// The parser is returned by value, so the underlying type
/// must be safely movable (no self-referential storage).
/// `BaseParser` is movable by construction; custom `lang.Parser`
/// wrappers must preserve this invariant.
pub fn parseProgram(allocator: std.mem.Allocator, source: []const u8) !struct { parser: Parser, sexp: Sexp } {
    var p = Parser.init(allocator, source);
    errdefer p.deinit();
    const sexp = try p.parseProgram();
    return .{ .parser = p, .sexp = sexp };
}

/// Convenience: instantiate the (lang-extended) parser and parse a whole
/// expr. Caller owns `result.parser` and must call `result.parser.deinit()`
/// when done with the returned tree (the tree references arena-allocated
/// memory owned by the parser).
///
/// The parser is returned by value, so the underlying type
/// must be safely movable (no self-referential storage).
/// `BaseParser` is movable by construction; custom `lang.Parser`
/// wrappers must preserve this invariant.
pub fn parseExpr(allocator: std.mem.Allocator, source: []const u8) !struct { parser: Parser, sexp: Sexp } {
    var p = Parser.init(allocator, source);
    errdefer p.deinit();
    const sexp = try p.parseExpr();
    return .{ .parser = p, .sexp = sexp };
}

